const items = $input.all();
const output = [];

for (const item of items) {
  let data = item.json;

  // Desenvolver body si n8n lo envuelve (común en webhooks)
  if (data.body !== undefined) {
    data = data.body;
  }

  const errors = [];
  const requiredFields = ["user", "badge", "description"];

  // Verificar campos requeridos
  for (const field of requiredFields) {
    if (data[field] === undefined || data[field] === null) {
      errors.push(`Falta el campo '${field}'`);
    }
  }

  if (errors.length === 0) {
    // Validar tipos
    if (typeof data["user"] !== "string" || data["user"].trim().length === 0) {
      errors.push(`'user' debe ser un string no vacío`);
    }
    if (typeof data["badge"] !== "string" || data["badge"].trim().length === 0) {
      errors.push(`'badge' debe ser un string no vacío`);
    }
    if (typeof data["description"] !== "string" || data["description"].trim().length === 0) {
      errors.push(`'description' debe ser un string no vacío`);
    }

    // Verificar campos extra no permitidos
    const allowedFields = ["user", "badge", "description"];
    const extraFields = Object.keys(data).filter(k => !allowedFields.includes(k));
    if (extraFields.length > 0) {
      errors.push(`Campos no permitidos: ${extraFields.join(", ")}`);
    }
  }

  if (errors.length > 0) {
    output.push({ json: { valid: false, error: errors.join("; "), data } });
  } else {
    output.push({ json: { valid: true, data } });
  }
}

return output;

const item = $input.first();
const { user, badge, description } = item.json.data;

// Construir texto publicable para la red social
const postText = `🏅 ¡Felicitaciones, ${user}! \n\nAcabás de obtener la insignia "${badge}" en DonaTrack. \n\n📌 ${description} \n\n¡Gracias por tu compromiso con quienes más lo necesitan! 💙 \n\n#DonaTrack #Donaciones #Solidaridad`;

// Construir prompt para generación de imagen
const imagePrompt = `Award badge icon for "${badge}", charity donation platform, golden medal with heart symbol, modern flat design, vibrant colors, celebration theme`;

// URL de imagen usando Pollinations.ai (gratuito, sin API key)
const imageWidth = 512;
const imageHeight = 512;
const encodedPrompt = encodeURIComponent(imagePrompt);
const imageUrl = `https://image.pollinations.ai/prompt/${encodedPrompt}?width=${imageWidth}&height=${imageHeight}&nologo=true`;

return [{
  json: {
    user,
    badge,
    description,
    postText,
    imagePrompt,
    imageUrl,
    generatedAt: new Date().toISOString()
  }
}];

